-- The old batch olive oil matches were divided by purchaseAmount=2.73 which is wrong for those cases
-- "HUILE D'OLIVE PURE 4 x 3 litres" = 12L case, unitPrice $50 means $50/case, per-L = $50/12 = $4.17/L
-- "HUILE D'OLIVE EXTRA VIERGE 16 litres / 14 kg" = 16L case, $72.89/case = $4.56/L
-- "OIL OLIVE EXTRA VIRGIN" at GFS = $17.78, likely a 3L tin = $5.93/L
-- "Summum 3L" = $12.74/3L = $4.25/L
-- So real per-L price is ~$4-6/L. The stored unitPrice was divided by 2.73 which is wrong for the 12L and 16L cases

-- Fix: update the match unitPrices to correct per-L values
UPDATE invoiceLineItemMatches SET unitPrice = 50.1026 / 12 WHERE matchedItemName = 'Olive oil' AND invoiceId = 60067;
UPDATE invoiceLineItemMatches SET unitPrice = 45.1099 / 12 WHERE matchedItemName = 'Olive oil' AND invoiceId = 60096;
UPDATE invoiceLineItemMatches SET unitPrice = 72.8938 / 16 WHERE matchedItemName = 'Olive oil' AND invoiceId = 60114;
UPDATE invoiceLineItemMatches SET unitPrice = 17.7802 / 3 WHERE matchedItemName = 'Olive oil' AND invoiceId = 90080;
UPDATE invoiceLineItemMatches SET unitPrice = 12.7436 / 3 WHERE matchedItemName = 'Olive oil' AND invoiceId = 90261;

-- Now recalculate olive oil inventory cost (unit is L, but stored as Kg with purchaseAmount=2.73)
-- Actually let's just use the corrected match prices
UPDATE inventoryItems SET 
  lastCost = (SELECT unitPrice FROM invoiceLineItemMatches WHERE matchedItemName = 'Olive oil' AND matchStatus = 'auto_matched' ORDER BY invoiceId DESC LIMIT 1),
  avgCost = (SELECT AVG(unitPrice) FROM invoiceLineItemMatches WHERE matchedItemName = 'Olive oil' AND matchStatus = 'auto_matched'),
  costPerUsableUnit = (SELECT unitPrice FROM invoiceLineItemMatches WHERE matchedItemName = 'Olive oil' AND matchStatus = 'auto_matched' ORDER BY invoiceId DESC LIMIT 1) / (yieldPct / 100),
  updatedAt = NOW()
WHERE name = 'Olive oil';

SELECT name, lastCost, avgCost, costPerUsableUnit FROM inventoryItems WHERE name = 'Olive oil';

